INSERT INTO tools (slug, name, tagline, description, website_url, affiliate_url, pricing_type, pricing_free_tier, pricing_starting_price, rating, review_count, featured, trending, editor_pick, tags, pros, cons, use_cases, updated_at)
VALUES

('intercom-fin', 'Intercom Fin', 'AI customer service agent that resolves queries automatically end-to-end',
 E'Intercom Fin is the AI agent built into Intercom''s customer service platform. Unlike chatbots that route to humans, Fin attempts to fully resolve customer queries end-to-end using GPT-4-class reasoning, the customer''s account context, and the company''s knowledge base. Fin handles refunds, account changes, troubleshooting, and policy questions autonomously, escalating to humans only when it cannot resolve confidently.\n\nThe accuracy comes from grounding: Fin reads the company''s help articles, internal docs, and past conversation patterns to ensure responses match brand policy. Companies using Fin report 40-60% deflection rates from human agents, with customer satisfaction scores comparable to human-handled tickets. The platform charges per resolution rather than per seat or per message, aligning vendor incentives with customer outcomes.\n\nFin sits inside the broader Intercom platform that includes the messaging inbox, ticketing, knowledge base, and outbound messaging. For companies already on Intercom, enabling Fin is a configuration change rather than a new vendor evaluation. Pricing per resolution at $0.99 makes ROI measurable: if your average human-handled ticket costs more than $1.50, Fin is cheaper.',
 'https://intercom.com/fin', 'https://intercom.com/fin',
 'paid', false, 99, 4.6, 3200, false, true, false,
 ARRAY['customer-support', 'ai-assistants', 'business'],
 ARRAY['Resolves queries end-to-end without human handoff in 40-60% of cases', 'Grounded in company knowledge base for accurate, on-brand responses', 'Per-resolution pricing aligns vendor incentives with customer outcomes', 'Native integration with rest of Intercom platform'],
 ARRAY['Per-resolution pricing can scale unexpectedly during ticket volume spikes', 'Best results require well-maintained knowledge base for grounding', 'Limited utility for companies not already on Intercom', 'Some queries require human empathy that Fin currently lacks'],
 ARRAY['Tier-1 support automation for SaaS companies', 'After-hours customer service coverage without overtime cost', 'Knowledge-base-driven answer automation for common policy questions'],
 NOW()),

('ada-ai', 'Ada', 'AI customer service automation platform for enterprise brands',
 E'Ada is an enterprise-focused AI customer service platform that competes directly with Intercom Fin and Zendesk AI agents. The platform builds AI agents trained on each company''s knowledge base, policies, and past conversations to handle customer inquiries across chat, email, voice, and social channels. Ada''s differentiator is depth of customization for enterprise brands with complex product catalogs and regulatory requirements.\n\nThe no-code builder lets customer service teams configure conversation flows, escalation rules, and brand voice without engineering involvement. Ada''s Reasoning Engine evaluates intent, sentiment, and context to choose between automated resolution, knowledge article surfacing, and agent handoff. The platform integrates with Salesforce, Zendesk, Shopify, Stripe, and 50+ enterprise systems to take actions on behalf of customers (issuing refunds, updating accounts, scheduling deliveries).\n\nAda works best for established brands with 1,000+ tickets per month and a mature support function. Smaller companies usually find Intercom Fin or Zendesk AI more accessible. Pricing is custom, scaling with conversation volume and integration depth - typical enterprise deployments start at $50K+ ARR.',
 'https://ada.cx', 'https://ada.cx',
 'paid', false, 0, 4.4, 1800, false, false, false,
 ARRAY['customer-support', 'ai-assistants', 'business'],
 ARRAY['Deep customization for enterprise brands with complex catalogs', 'Action-taking integrations: refunds, account updates, scheduling', 'Multi-channel support: chat, email, voice, social', 'No-code builder accessible to support managers without engineering'],
 ARRAY['Custom enterprise pricing not transparent until sales call', 'Implementation timeline 8-16 weeks typical for full deployment', 'Best fit requires 1,000+ monthly tickets to justify the investment', 'Platform complexity creates ongoing tuning workload for support ops'],
 ARRAY['Enterprise customer service automation with action-taking AI agents', 'Multi-channel support consolidation for large brands', 'Tier-1 deflection across chat, email, and social channels'],
 NOW()),

('forethought-ai', 'Forethought', 'AI agent for ticket triage, deflection, and assistance for support teams',
 E'Forethought is a generative AI platform built specifically for customer support teams. The product splits into 3 modules: Solve (deflection AI for self-service), Triage (intent classification and routing), and Assist (real-time agent assistance during conversations). Together they target the full ticket lifecycle from initial customer query through resolution.\n\nSolve uses LLM technology to answer customer questions before they reach an agent, drawing from the company''s help center, internal documents, and past resolved tickets. Triage classifies incoming tickets by intent, urgency, and customer tier, routing to the right agent or queue automatically. Assist sits in the agent''s ticket view providing suggested responses, knowledge article surfacing, and macro recommendations during live conversations.\n\nForethought integrates with Zendesk, Salesforce Service Cloud, Freshdesk, and Intercom. The platform measures impact through deflection rate, average handle time, and CSAT - and customer testimonials consistently report 30-50% deflection lift over baseline rule-based bots. Pricing is per-resolution for Solve, per-seat for Assist, with custom enterprise discounts.',
 'https://forethought.ai', 'https://forethought.ai',
 'paid', false, 0, 4.3, 920, false, false, false,
 ARRAY['customer-support', 'ai-assistants', 'productivity'],
 ARRAY['Three modules cover full ticket lifecycle: deflection, routing, agent assist', 'Strong integrations with Zendesk, Salesforce, Freshdesk, Intercom', 'Real-time agent assistance reduces handle time on complex tickets', 'Per-resolution pricing for Solve aligns cost with measurable outcomes'],
 ARRAY['Custom pricing model can be opaque versus transparent per-seat tools', 'Best results require connected knowledge base and historical ticket data', 'Less established brand than Ada or Intercom for enterprise procurement', 'Module-based pricing can add up if you adopt the full suite'],
 ARRAY['Ticket deflection at scale for support teams with strong knowledge bases', 'Real-time agent assistance for handling complex multi-stage tickets', 'Intent-based ticket routing for support orgs with multiple specialty queues'],
 NOW()),

('moveworks', 'Moveworks', 'AI copilot for IT support, HR, and employee service automation',
 E'Moveworks is an AI copilot for internal employee support - IT helpdesk, HR queries, and operational tickets - rather than external customer support. The platform sits in Slack, Microsoft Teams, and email, intercepting employee questions and either resolving them autonomously or routing to the right system or team. For companies with 1,000+ employees, Moveworks measurably reduces IT and HR ticket volume by 30-50%.\n\nWhat makes Moveworks distinct is the action-taking layer. The AI does not just answer questions - it can reset passwords, provision software access, look up PTO balances, file tickets in ServiceNow, and update HR records, all from a chat conversation. Integrations span 100+ enterprise systems including Okta, Workday, ServiceNow, Salesforce, Confluence, and Microsoft Graph.\n\nMoveworks is enterprise-only by design. Pricing is custom and starts in the high six-figure range. Implementation requires IT, HR, and security team buy-in plus 3-6 months of integration work. For Fortune 1000 companies wrestling with IT support cost or HR query volume, the ROI is straightforward to calculate.',
 'https://moveworks.com', 'https://moveworks.com',
 'paid', false, 0, 4.5, 680, false, false, false,
 ARRAY['customer-support', 'ai-assistants', 'business'],
 ARRAY['Action-taking AI: resets passwords, provisions access, files tickets autonomously', 'Native Slack and Teams interface meets employees where they work', 'Reduces IT and HR ticket volume by measurable 30-50% in deployments', '100+ enterprise system integrations including Okta, Workday, ServiceNow'],
 ARRAY['Enterprise-only with high six-figure annual pricing minimum', 'Implementation timeline 3-6 months typical for full integration', 'Best fit only for organizations with 1,000+ employees', 'Complexity creates ongoing tuning and governance workload'],
 ARRAY['IT helpdesk automation for large enterprises', 'HR query resolution and self-service for employee questions', 'Internal operations ticket routing and action automation'],
 NOW()),

('decagon-ai', 'Decagon', 'AI customer support agents trained on your knowledge base and product data',
 E'Decagon builds AI customer support agents for high-growth and enterprise companies. The platform trains agents on the company''s help center, product documentation, past tickets, and internal Slack threads, then deploys them across chat, email, and Slack channels. Decagon focuses on autonomous resolution rather than chatbot-style scripting - the AI reasons through novel queries using the company''s actual knowledge.\n\nWhat differentiates Decagon is the analytics layer. The platform tracks every AI conversation, identifies knowledge gaps automatically (questions the AI cannot answer), and surfaces them to the support ops team to resolve. This creates a continuous improvement loop where the AI gets smarter as the knowledge base improves. Customer testimonials consistently report 60-80% deflection rates after 90 days of operation.\n\nDecagon competes with Ada, Forethought, and Intercom Fin, primarily for high-growth scaleups and mid-market enterprises with dedicated support ops teams. Pricing is custom; typical deployments start around $50K-$100K ARR. Implementation involves 4-8 weeks of knowledge base curation and integration work.',
 'https://decagon.ai', 'https://decagon.ai',
 'paid', false, 0, 4.7, 420, false, true, false,
 ARRAY['customer-support', 'ai-assistants', 'analytics'],
 ARRAY['Autonomous resolution rather than scripted chatbot flows', 'Knowledge gap detection feeds continuous improvement loop', 'Native integrations with Zendesk, Intercom, Slack, Front', 'Strong analytics dashboard for support ops teams'],
 ARRAY['Custom pricing requires sales call to evaluate fit', 'Best fit for companies with 5,000+ tickets per month', 'Implementation requires support ops team time for knowledge base curation', 'Newer brand than Ada or Intercom in enterprise procurement processes'],
 ARRAY['Tier-1 support deflection for high-growth SaaS companies', 'Knowledge gap detection for support content teams', 'Multi-channel AI agent deployment across chat, email, and Slack'],
 NOW()),

('ultimate-ai', 'Ultimate', 'Customer support automation platform for global ecommerce and SaaS brands',
 E'Ultimate is a customer support automation platform with strong multilingual capabilities and ecommerce-specific features. The AI handles customer queries across chat, email, social media, and messaging apps in 100+ languages with native fluency. For global brands serving customers across multiple regions, Ultimate''s language coverage is genuinely differentiated versus competitors that offer translation as an afterthought.\n\nThe ecommerce features include order status lookups, return processing, product recommendations, and inventory queries via integrations with Shopify, BigCommerce, Magento, and major fulfillment providers. The AI can take actions on customer accounts directly rather than handing off to agents for routine ecommerce tasks.\n\nUltimate fits mid-market ecommerce brands and SaaS companies with 1,000+ monthly tickets. The platform integrates with Zendesk, Salesforce Service Cloud, Freshdesk, and Gorgias for ecommerce-native support stacks. Pricing is custom; typical deployments start around $40K ARR. The company was acquired by Zendesk in 2024, which has strengthened the Zendesk integration depth.',
 'https://ultimate.ai', 'https://ultimate.ai',
 'paid', false, 0, 4.4, 540, false, false, false,
 ARRAY['customer-support', 'ai-assistants', 'ecommerce'],
 ARRAY['Strong multilingual support: 100+ languages with native fluency', 'Ecommerce-native integrations with Shopify, BigCommerce, fulfillment APIs', 'Action-taking on orders, returns, accounts without human handoff', 'Acquired by Zendesk: deepest integration in Zendesk ecosystem'],
 ARRAY['Custom enterprise pricing not transparent until sales call', 'Best fit for global brands; less ROI for single-region SMBs', 'Acquisition by Zendesk may shift product roadmap toward Zendesk integration', 'Some smaller languages have lower fluency than top-10 supported languages'],
 ARRAY['Multilingual customer support automation for global ecommerce brands', 'Order management and return processing automation', 'Multi-channel AI agent deployment across chat, email, and social'],
 NOW()),

('yellow-ai', 'Yellow.ai', 'Conversational AI platform for customer and employee service across channels',
 E'Yellow.ai is a conversational AI platform that competes with Intercom, Ada, and Salesforce Einstein for enterprise customer and employee service deployments. The platform supports 35+ channels (chat, voice, WhatsApp, SMS, social, email) with a unified bot-building interface. The voice AI capability is particularly strong - Yellow handles inbound and outbound voice interactions with natural-sounding speech across 135+ languages.\n\nThe platform splits into customer-facing and employee-facing modules. The customer module handles support, sales, and marketing conversations. The employee module handles HR, IT, and internal queries similar to Moveworks. For organizations wanting one platform across both customer and employee AI use cases, Yellow''s consolidation can reduce vendor sprawl.\n\nYellow.ai fits large enterprises in Asia-Pacific and emerging markets where the company has its strongest presence and partner network. North American and European deployments compete more directly with Intercom and Ada. Custom enterprise pricing typical; deployments start around $30K ARR for mid-market and scale into seven figures for global enterprises.',
 'https://yellow.ai', 'https://yellow.ai',
 'paid', false, 0, 4.2, 1100, false, false, false,
 ARRAY['customer-support', 'ai-assistants', 'voice-audio'],
 ARRAY['35+ channels supported including voice, WhatsApp, social', 'Strong voice AI with 135+ language support', 'Single platform for both customer and employee service automation', 'Strong presence in Asia-Pacific and emerging markets'],
 ARRAY['Custom pricing varies by region and module mix', 'Brand recognition lower in North America vs Intercom or Ada', 'Platform breadth creates a steeper learning curve', 'Some legacy bot-building paradigms feel dated versus newer LLM-native tools'],
 ARRAY['Multi-channel customer service automation for global enterprises', 'Voice AI for inbound and outbound contact center automation', 'Employee service automation as alternative to Moveworks'],
 NOW()),

('glia', 'Glia', 'Digital customer service platform combining chat, voice, and screen sharing for finance',
 E'Glia is a digital customer service platform built specifically for banks, credit unions, and financial services companies. The platform combines AI chat, voice, video, and co-browsing into a unified customer engagement layer. The financial services focus is the differentiator: Glia''s features, integrations, and compliance posture all target regulated finance use cases rather than general-purpose customer service.\n\nThe AI handles routine banking queries (account balances, transaction history, branch hours) autonomously while the co-browsing capability lets human agents share screens with customers to walk them through complex tasks like loan applications or investment account setups. This hybrid AI-plus-human model fits the trust and accuracy requirements of finance better than pure-AI deflection platforms.\n\nGlia integrates with major banking core systems (FIS, Jack Henry, Fiserv) and CRM platforms. Pricing is custom and structured around channels, conversation volume, and feature mix. Typical deployments at credit unions start around $50K ARR; large banks deploy in the seven-figure range.',
 'https://glia.com', 'https://glia.com',
 'paid', false, 0, 4.5, 480, false, false, false,
 ARRAY['customer-support', 'fintech', 'ai-assistants'],
 ARRAY['Purpose-built for banks, credit unions, and financial services', 'Co-browsing capability for guided customer assistance on complex tasks', 'Compliance-first design fits regulated finance requirements', 'Strong integrations with banking core systems and finance CRMs'],
 ARRAY['Vertical focus on finance limits applicability to other industries', 'Custom enterprise pricing not transparent until sales call', 'Feature breadth creates learning curve for support managers', 'Less LLM-native than newer competitors like Decagon or Intercom Fin'],
 ARRAY['Banking customer service automation with hybrid AI-plus-human flow', 'Credit union digital member service across web and mobile apps', 'Co-browsing for guided loan or investment account setup assistance'],
 NOW()),

('lang-io', 'Lang.io', 'AI tagging and routing platform for customer support tickets',
 E'Lang.io is an AI infrastructure platform for customer support that focuses on a specific job: automatically tagging, routing, and analyzing every incoming ticket. Unlike full automation platforms (Ada, Intercom Fin) that try to resolve tickets autonomously, Lang sits as a layer on top of existing tools (Zendesk, Salesforce, Front) and improves how human agents and existing automation handle the work.\n\nThe AI tags each ticket by intent, sentiment, urgency, customer tier, and topic with high accuracy after a brief training period on the company''s historical tickets. Routing engines use these tags to send tickets to the right queue, agent, or automation. The analytics dashboard surfaces trends - common issues, emerging product problems, escalation patterns - that help support leaders proactively address root causes.\n\nLang.io fits support orgs with 5,000+ tickets per month where manual tagging is unworkable but full AI deflection feels too aggressive. Pricing is per-ticket or per-seat depending on deployment. The platform integrates with Zendesk, Front, Help Scout, and Salesforce as the most common deployments.',
 'https://lang.ai', 'https://lang.ai',
 'paid', false, 0, 4.4, 280, false, false, false,
 ARRAY['customer-support', 'analytics', 'ai-assistants'],
 ARRAY['Augments existing helpdesk rather than replacing it - lower switching cost', 'High-accuracy AI tagging surfaces patterns invisible in raw ticket data', 'Per-ticket pricing aligns cost with usage volume', 'Strong analytics for support leadership identifying systemic issues'],
 ARRAY['Less impact for orgs with manageable ticket volumes (under 1,000/month)', 'Newer brand with smaller community than Ada or Intercom', 'Best results require historical ticket data for training', 'Does not deflect tickets autonomously - augments human workflow'],
 ARRAY['Ticket tagging and routing automation for high-volume support orgs', 'Pattern detection and root cause analysis for support leadership', 'Augmenting existing Zendesk or Salesforce deployments without replacing them'],
 NOW()),

('espressive', 'Espressive', 'AI virtual employee assistant for IT, HR, and workplace service',
 E'Espressive is an AI-powered virtual employee assistant focused on internal employee service across IT, HR, facilities, and procurement. The Barista AI agent runs in Slack, Microsoft Teams, and a web portal, answering employee questions and taking actions across enterprise systems autonomously. Where Moveworks targets large enterprises with custom integration work, Espressive offers a more standardized deployment for mid-market companies.\n\nThe pre-built knowledge packs cover the most common employee questions across HR (PTO, benefits, payroll), IT (password resets, software access), facilities (room booking, parking), and procurement (supplier lookups, expense policies). Companies typically see 50-70% deflection on routine questions within 90 days, freeing IT and HR teams to focus on strategic work.\n\nEspressive integrates with ServiceNow, Workday, Okta, Zendesk, and 80+ enterprise systems. Pricing is custom and scales with employee count; typical mid-market deployments start around $25K ARR. Implementation timeline is 6-12 weeks - faster than Moveworks but slower than off-the-shelf chatbots.',
 'https://espressive.com', 'https://espressive.com',
 'paid', false, 0, 4.3, 380, false, false, false,
 ARRAY['customer-support', 'ai-assistants', 'productivity'],
 ARRAY['Pre-built knowledge packs accelerate deployment vs custom-built alternatives', 'Mid-market sweet spot less competitive than Moveworks or Salesforce', 'Native Slack and Teams interface meets employees where they work', 'Strong integrations with ServiceNow, Workday, Okta, and 80+ systems'],
 ARRAY['Less customization depth than Moveworks for very large enterprises', 'Custom pricing not transparent until sales evaluation', 'Best results require IT and HR team buy-in for content tuning', 'Knowledge pack pre-built coverage may not fit specialized industries'],
 ARRAY['Employee IT and HR self-service automation for mid-market companies', 'Internal helpdesk deflection for routine policy and process questions', 'Workplace service automation across facilities, procurement, and finance'],
 NOW()) ON CONFLICT (slug) DO NOTHING;
